namespace TicketClassifier.Models;

public record ClassifyRequest(string Subject, string Description, int Priority);

public record ClassifyResponse(string Category, Dictionary<string, float> Confidence);

public record TrainResponse(string Message, EvaluationMetricsDto Metrics);

public record EvaluationMetricsDto(
    double MicroAccuracy,
    double MacroAccuracy,
    double LogLoss,
    double LogLossReduction);

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelService
{
    private readonly MLContext _mlContext = new(seed: 42);
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ILogger<TicketModelService> _logger;
    private readonly object _lock = new();

    private MulticlassClassificationMetrics? _latestMetrics;
    private string[] _classLabels = [];

    public TicketModelService(ILogger<TicketModelService> logger, IWebHostEnvironment env)
    {
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "ticket-model.zip");
        _logger = logger;
    }

    public string ModelPath => _modelPath;
    public MulticlassClassificationMetrics? LatestMetrics { get { lock (_lock) return _latestMetrics; } }
    public string[] ClassLabels { get { lock (_lock) return _classLabels; } }

    public MulticlassClassificationMetrics TrainAndEvaluate()
    {
        lock (_lock)
        {
            var data = _mlContext.Data.LoadFromTextFile<TicketData>(
                _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

            var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

            var pipeline = _mlContext.Transforms.Conversion
                    .MapValueToKey("Label", nameof(TicketData.Category))
                .Append(_mlContext.Transforms.Text.FeaturizeText(
                    "SubjectFeaturized", nameof(TicketData.Subject)))
                .Append(_mlContext.Transforms.Text.FeaturizeText(
                    "DescriptionFeaturized", nameof(TicketData.Description)))
                .Append(_mlContext.Transforms.Concatenate(
                    "Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
                .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
                .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

            var model = pipeline.Fit(split.TrainSet);

            // Extract class labels from Score column slot names
            var transformedData = model.Transform(split.TrainSet);
            var scoreColumn = transformedData.Schema["Score"];
            var slotNames = new VBuffer<ReadOnlyMemory<char>>();
            scoreColumn.GetSlotNames(ref slotNames);
            _classLabels = new string[slotNames.Length];
            for (int i = 0; i < slotNames.Length; i++)
                _classLabels[i] = slotNames.GetItemOrDefault(i).ToString();

            // Evaluate on held-out test set
            var predictions = model.Transform(split.TestSet);
            _latestMetrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

            _logger.LogInformation(
                "Model trained — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}",
                _latestMetrics.MicroAccuracy, _latestMetrics.MacroAccuracy, _latestMetrics.LogLoss);

            _mlContext.Model.Save(model, data.Schema, _modelPath);
            _logger.LogInformation("Model saved to {Path}", _modelPath);

            return _latestMetrics;
        }
    }
}

