using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/tickets")]
public class TicketClassifierController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;
    private readonly TicketModelService _modelService;

    public TicketClassifierController(
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool,
        TicketModelService modelService)
    {
        _predictionPool = predictionPool;
        _modelService = modelService;
    }

    [HttpPost("classify")]
    public ActionResult<ClassifyResponse> Classify([FromBody] ClassifyRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        var labels = _modelService.ClassLabels;
        for (int i = 0; i < labels.Length && i < prediction.Score.Length; i++)
            confidence[labels[i]] = prediction.Score[i];

        return Ok(new ClassifyResponse(prediction.Category, confidence));
    }

    [HttpPost("train")]
    public ActionResult<TrainResponse> Train()
    {
        var metrics = _modelService.TrainAndEvaluate();

        return Ok(new TrainResponse(
            "Model retrained successfully",
            new EvaluationMetricsDto(
                metrics.MicroAccuracy,
                metrics.MacroAccuracy,
                metrics.LogLoss,
                metrics.LogLossReduction)));
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationMetricsDto> GetMetrics()
    {
        var metrics = _modelService.LatestMetrics;
        if (metrics is null)
            return NotFound("No model has been trained yet.");

        return Ok(new EvaluationMetricsDto(
            metrics.MicroAccuracy,
            metrics.MacroAccuracy,
            metrics.LogLoss,
            metrics.LogLossReduction));
    }
}

